# ──────────────────────────────────────────────────────────────────────────
# Rename der Top-Nav-Einträge (v6.7.65):
#   /tenant    : "Management"    → "Printix Management"
#   /my        : (bislang ohne Label) → "Printjob Management"
# Marken-konsistenz: "Printix" ist unser Produkt, "Management" war zu
# generisch. "/my" heisst jetzt "Printjob Management", weil wir dort
# deutlich mehr machen als nur Delegate (Upload, Jobs, Reports, …).
# Labels bleiben über alle 8 Sprachen hinweg identisch, weil wir hier
# bewusst mit englischen Produkt-Begriffen arbeiten.
# ──────────────────────────────────────────────────────────────────────────
NAV_RENAME_TRANSLATIONS: dict[str, dict[str, str]] = {}
for _lang in ("de", "en", "es", "fr", "it", "nl", "no", "sv"):
    NAV_RENAME_TRANSLATIONS[_lang] = {
        "nav_my_portal": "Printjob Management",
    }

for lang, extra in NAV_RENAME_TRANSLATIONS.items():
    TRANSLATIONS.setdefault(lang, {}).update(extra)


